import{_ as l,o as i,c as e,a3 as t}from"./chunks/framework.BTFg6ESq.js";const c=JSON.parse('{"title":"工具管理","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/settings/tool-management.md","filePath":"user-guide/settings/tool-management.md","lastUpdated":1780241474000}'),r={name:"user-guide/settings/tool-management.md"};function o(h,a,n,d,s,u){return i(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="工具管理" tabindex="-1">工具管理 <a class="header-anchor" href="#工具管理" aria-label="Permalink to &quot;工具管理&quot;">​</a></h1><p>工具管理用于控制主页工具卡片的显示状态和排列顺序。它不会卸载工具，也不会删除工具数据，只影响你在主页和常用入口中看到工具的方式。</p><h2 id="入口" tabindex="-1">入口 <a class="header-anchor" href="#入口" aria-label="Permalink to &quot;入口&quot;">​</a></h2><ol><li>点击标题栏右侧的设置图标进入设置。</li><li>在左侧导航栏中选择「工具模块」。</li><li>右侧会显示全部已注册工具卡片。</li></ol><p>页面顶部会显示已启用数量和工具总数，例如 <code>18/34</code>。</p><h2 id="显示或隐藏工具" tabindex="-1">显示或隐藏工具 <a class="header-anchor" href="#显示或隐藏工具" aria-label="Permalink to &quot;显示或隐藏工具&quot;">​</a></h2><p>每个工具以卡片形式展示。卡片被选中时，会在主页显示；取消选中后，会从主页工具网格中隐藏。</p><p>常用操作：</p><ul><li>点击单个工具卡片：切换显示或隐藏。</li><li>点击「全选」：把所有工具显示到主页。</li><li>点击「全不选」：隐藏所有工具卡片。</li><li>查看顶部数量：确认当前启用数量。</li></ul><p>隐藏工具适合把低频工具收起来，让主页更清爽。工具本身仍然存在，重新勾选即可恢复。</p><h2 id="调整工具顺序" tabindex="-1">调整工具顺序 <a class="header-anchor" href="#调整工具顺序" aria-label="Permalink to &quot;调整工具顺序&quot;">​</a></h2><p>工具卡片左侧有排序手柄。将鼠标移到卡片上，拖动排序手柄即可调整顺序。</p><p>排序会影响：</p><ul><li>主页工具卡片排列。</li><li>已打开工具侧边栏中的默认顺序。</li><li>部分工具选择器中使用的工具顺序。</li></ul><p>拖拽结束后会自动保存。如果顺序没有变化，系统不会重复写入配置。</p><h2 id="重置顺序" tabindex="-1">重置顺序 <a class="header-anchor" href="#重置顺序" aria-label="Permalink to &quot;重置顺序&quot;">​</a></h2><p>点击「重置顺序」会清除自定义排序，恢复为项目默认工具顺序。</p><p>它只重置顺序，不会改变工具显示或隐藏状态。也就是说，如果某个工具已经被你隐藏，重置顺序后它仍然保持隐藏。</p><h2 id="推荐整理方式" tabindex="-1">推荐整理方式 <a class="header-anchor" href="#推荐整理方式" aria-label="Permalink to &quot;推荐整理方式&quot;">​</a></h2><h3 id="ai-对话用户" tabindex="-1">AI 对话用户 <a class="header-anchor" href="#ai-对话用户" aria-label="Permalink to &quot;AI 对话用户&quot;">​</a></h3><p>建议保留：</p><ul><li>LLM 对话</li><li>知识库</li><li>资产管理器</li><li>多模态转写</li><li>Token 计算器</li><li>媒体生成中心</li></ul><h3 id="开发者" tabindex="-1">开发者 <a class="header-anchor" href="#开发者" aria-label="Permalink to &quot;开发者&quot;">​</a></h3><p>建议保留：</p><ul><li>JSON 格式化</li><li>正则批量替换</li><li>文本差异对比</li><li>代码格式化</li><li>Git 分析器</li><li>API 测试工具</li><li>服务注册表浏览器</li></ul><h3 id="创作者" tabindex="-1">创作者 <a class="header-anchor" href="#创作者" aria-label="Permalink to &quot;创作者&quot;">​</a></h3><p>建议保留：</p><ul><li>智能 OCR</li><li>多模态转写</li><li>富文本渲染测试</li><li>图片色彩分析</li><li>媒体生成中心</li><li>Web Canvas</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li>工具管理不会关闭正在运行的后台服务。</li><li>隐藏工具不等于禁用工具启动项；自动启动行为请到「启动项管理」中单独调整。</li><li>插件工具或新增工具注册后，可能会以默认显示状态出现在列表中。</li><li>如果工具列表顺序异常，可以先点「重置顺序」，再重新拖拽常用工具到前面。</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="隐藏工具后还能通过链接打开吗" tabindex="-1">隐藏工具后还能通过链接打开吗？ <a class="header-anchor" href="#隐藏工具后还能通过链接打开吗" aria-label="Permalink to &quot;隐藏工具后还能通过链接打开吗？&quot;">​</a></h3><p>通常可以。隐藏只影响主页展示，不代表工具路由或内部能力被移除。</p><h3 id="为什么隐藏工具后它仍在后台运行" tabindex="-1">为什么隐藏工具后它仍在后台运行？ <a class="header-anchor" href="#为什么隐藏工具后它仍在后台运行" aria-label="Permalink to &quot;为什么隐藏工具后它仍在后台运行？&quot;">​</a></h3><p>该工具可能注册了启动项，或被其他模块调用。请同时检查「启动项管理」和相关工具设置。</p><h3 id="工具排序没有保存怎么办" tabindex="-1">工具排序没有保存怎么办？ <a class="header-anchor" href="#工具排序没有保存怎么办" aria-label="Permalink to &quot;工具排序没有保存怎么办？&quot;">​</a></h3><p>确认拖拽的是排序手柄，并在拖拽结束后看到成功提示。如果仍未保存，查看日志配置中是否有设置写入错误。</p><h3 id="可以恢复默认显示状态吗" tabindex="-1">可以恢复默认显示状态吗？ <a class="header-anchor" href="#可以恢复默认显示状态吗" aria-label="Permalink to &quot;可以恢复默认显示状态吗？&quot;">​</a></h3><p>目前页面提供顺序重置。显示状态可以通过「全选」快速恢复为全部显示，再按需要手动隐藏少数工具。</p>',39)])])}const b=l(r,[["render",o]]);export{c as __pageData,b as default};
